// Validate webhook payload — must include slug.
const body = $input.first().json.body || $input.first().json;
const slug = (body.slug || '').trim();

if (!slug) {
  throw new Error('Missing required field: slug');
}
if (!/^[a-z0-9-]+$/.test(slug)) {
  throw new Error(`Invalid slug "${slug}" — lowercase letters, numbers, and hyphens only`);
}

return [{ json: { slug, filename: `${slug}.json` } }];

// Make sure we actually found exactly one matching file.
const items = $input.all();
if (!items.length) {
  throw new Error('No file found in Drive folder for slug ' + $('Validate slug').first().json.slug);
}
// Match by exact filename so slug "abc" doesn't grab "abc-extra.json".
const target = $('Validate slug').first().json.filename;
const match = items.find(it => (it.json.name || '') === target);
if (!match) {
  throw new Error(`File "${target}" not found in folder. Found: ${items.map(i => i.json.name).join(', ')}`);
}
return [{ json: { fileId: match.json.id, name: match.json.name } }];

// Convert the downloaded binary file into a parsed JSON payload
// and merge the slug from the webhook in.
const item = $input.first();
const binaryKey = Object.keys(item.binary || {})[0];
if (!binaryKey) throw new Error('No binary data returned from Drive download');

const buf = await this.helpers.getBinaryDataBuffer(0, binaryKey);
let payload;
try {
  payload = JSON.parse(buf.toString('utf8'));
} catch (e) {
  throw new Error('Drive file is not valid JSON: ' + e.message);
}

const slug = $('Validate slug').first().json.slug;

// Always force the slug from the webhook (single source of truth).
const body = {
  slug,
  title: payload.title || '',
  metaTitle: payload.metaTitle || payload.title || '',
  metaDescription: payload.metaDescription || payload.subtitle || '',
  subtitle: payload.subtitle || '',
  category: payload.category || 'General',
  date: payload.date || new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' }),
  readTime: payload.readTime || '5 min read',
  image: payload.image || '',
  content: payload.content || '',
  faqs: Array.isArray(payload.faqs) ? payload.faqs : [],
};

if (!body.title || !body.content) {
  throw new Error('Drive JSON must include title and content');
}

return [{ json: body }];

// Inspect the publish response. If it's a 409 (already exists), fall through
// to a PATCH update so the workflow is idempotent.
const resp = $input.first().json;
const status = resp.statusCode || resp.status;
const body = resp.body || resp;

if (status >= 200 && status < 300) {
  return [{ json: { action: 'created', status, slug: body.slug, body } }];
}
if (status === 409) {
  return [{ json: { action: 'needs_update', status, slug: $('Validate slug').first().json.slug, body } }];
}
throw new Error(`Publish failed (HTTP ${status}): ${JSON.stringify(body).slice(0, 400)}`);
